"use client";

import { memo, useCallback, useMemo, useState } from "react";
import { cn } from "@/lib/utils";
import { CategoryChip } from "./parts/category-chip";
import type {
  CategoryCloudItem,
  CategoryCloudProps,
  NormalizedItem,
} from "./types";

const defaultFormatCount = (count: number): string => ` (${count})`;

const normalizeItems = (
  items: CategoryCloudItem[] | string[],
): NormalizedItem[] =>
  items.map((entry) => {
    if (typeof entry === "string") {
      return { value: entry, label: entry, count: undefined };
    }
    return {
      value: entry.value,
      label: entry.label ?? entry.value,
      count: entry.count,
    };
  });

/**
 * CategoryCloud01 — always-visible flex-wrap of clickable category chips
 * with optional counts. Single-select, controlled-or-uncontrolled.
 *
 * Pass `string[]` as shorthand for items without counts:
 *   <CategoryCloud01 items={["All", "Tech", "Design"]} />
 *
 * Or full form for counts + display labels:
 *   <CategoryCloud01 items={[{ value: "tech", label: "Technology", count: 12 }]} />
 */
function CategoryCloud01Impl(props: CategoryCloudProps) {
  const {
    items,
    value: controlledValue,
    defaultValue = null,
    onChange,
    toggleable = true,
    title,
    headingAs = "h3",
    formatCount = defaultFormatCount,
    ariaLabel,
    className,
    titleClassName,
  } = props;

  const [internalValue, setInternalValue] = useState<string | null>(defaultValue);
  const isControlled = controlledValue !== undefined;
  const value = isControlled ? controlledValue : internalValue;

  const normalized = useMemo(() => normalizeItems(items), [items]);

  const handleClick = useCallback(
    (next: string) => {
      const resolved =
        toggleable && value === next ? null : next;
      if (!isControlled) setInternalValue(resolved);
      onChange?.(resolved);
    },
    [isControlled, onChange, toggleable, value],
  );

  const HeadingTag = headingAs;
  const groupLabel = ariaLabel ?? title ?? "Categories";

  return (
    <div className={className}>
      {title ? (
        <HeadingTag
          className={cn(
            "mb-4 border-b border-border pb-2 font-serif text-lg font-bold text-foreground",
            titleClassName,
          )}
        >
          {title}
        </HeadingTag>
      ) : null}
      <div
        role="group"
        aria-label={groupLabel}
        className="flex flex-wrap gap-2"
      >
        {normalized.map((item) => (
          <CategoryChip
            key={item.value}
            item={item}
            isActive={value === item.value}
            countLabel={item.count !== undefined ? formatCount(item.count) : ""}
            onClick={() => handleClick(item.value)}
          />
        ))}
      </div>
    </div>
  );
}

export const CategoryCloud01 = memo(CategoryCloud01Impl);
CategoryCloud01.displayName = "CategoryCloud01";

export default CategoryCloud01;

export { CategoryCloud01, default } from "./category-cloud-01";
export type {
  CategoryCloudHeadingLevel,
  CategoryCloudItem,
  CategoryCloudProps,
} from "./types";
export { meta } from "./meta";

export type CategoryCloudHeadingLevel = "h2" | "h3" | "h4";

export interface CategoryCloudItem {
  /** Stable identifier, used as the selection value. */
  value: string;
  /** Display text. Defaults to `value` if not provided. */
  label?: string;
  /** Optional count rendered after the label. */
  count?: number;
}

export interface CategoryCloudProps {
  /** Categories to render. Pass `string[]` as shorthand for `[{value,label}]`. */
  items: CategoryCloudItem[] | string[];

  /** Controlled selection value. Pass null to clear. */
  value?: string | null;
  /** Uncontrolled initial selection. Default: null. */
  defaultValue?: string | null;
  /** Selection change callback. Fires with null when re-clicking active (if toggleable). */
  onChange?: (value: string | null) => void;

  /** Whether re-clicking the active chip clears the selection. Default: true. */
  toggleable?: boolean;

  /** Optional title rendered above the cloud. */
  title?: string;
  /** Heading semantic level. Default: 'h3'. */
  headingAs?: CategoryCloudHeadingLevel;

  /** Custom count formatter. Default: `(count) => \` (\${count})\``. */
  formatCount?: (count: number) => string;

  /** ARIA group label. Defaults to `title` if provided, else 'Categories'. */
  ariaLabel?: string;

  /** Override classes for the root container. */
  className?: string;
  /** Override classes for the title heading. */
  titleClassName?: string;
}

/** Internal normalized item shape — both `string[]` and `CategoryCloudItem[]` flatten to this. */
export interface NormalizedItem {
  value: string;
  label: string;
  count: number | undefined;
}

import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import type { NormalizedItem } from "../types";

/**
 * One chip in the cloud. Native `<button>` for keyboard semantics +
 * `<Badge>` inside for visual.
 */
export function CategoryChip({
  item,
  isActive,
  countLabel,
  onClick,
}: {
  item: NormalizedItem;
  isActive: boolean;
  countLabel: string;
  onClick: () => void;
}) {
  return (
    <button
      type="button"
      aria-pressed={isActive}
      onClick={onClick}
      className="rounded-full outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
    >
      <Badge
        variant={isActive ? "default" : "secondary"}
        className={cn("cursor-pointer", isActive ? "" : "hover:bg-secondary/80")}
      >
        {item.label}
        {countLabel}
      </Badge>
    </button>
  );
}
